		}
		window.addEventListener('scroll', this.handleScroll)
		setTimeout(()=>{
			this.handleScroll()
		},100)
	},
	computed: {
		avatar(){
			return this.$storage.get('headportrait')?this.$storage.get('headportrait'):''
		},
	},
	methods:{
		handleScroll() {
			let arr = [
				{id:'home-title',css:'animate__fadeInUp'},
				{id:'statis1',css:'animate__fadeInUp'},
				{id:'ceshifenxiChart1',css:'animate__fadeInUp'},
			]
			
			for (let i in arr) {
				let doc = document.getElementById(arr[i].id)
				if (doc) {
					let top = doc.offsetTop
					let win_top = window.innerHeight + window.pageYOffset
					// console.log(top,win_top)
					if (win_top > top && doc.classList.value.indexOf(arr[i].css) < 0) {
						// console.log(doc)
						doc.classList.add(arr[i].css)
					}
				}
			}
		},
		// 统计图动画
		myChartInterval(type, xAxisData, seriesData, myChart) {
			this.$nextTick(() => {
				setInterval(() => {
					let xAxis = xAxisData.shift()
					xAxisData.push(xAxis)
					let series = seriesData.shift()
					seriesData.push(series)
				
					if (type == 1) {
						myChart.setOption({
							xAxis: [{
								data: xAxisData
							}],
							series: [{
								data: seriesData
							}]
						});
					}
					if (type == 2) {
						myChart.setOption({
							yAxis: [{
								data: xAxisData
							}],
							series: [{
								data: seriesData
							}]
						});
					}
				}, $template2.back.board.bar.base.interval);
			})
		},
		init(){
			if(this.$storage.get('Token')){
				this.$http({
					url: `${this.$storage.get('sessionTable')}/session`,
					method: "get"
				}).then(({ data }) => {
					if (data && data.code != 0) {
						router.push({ name: 'login' })
					}
				});
			}else{
				router.push({ name: 'login' })
			}
		},
		getceshifenxiCount() {
			this.$http({
				url: `ceshifenxi/count`,
				method: "get"
			}).then(({
				data
			}) => {
				if (data && data.code == 0) {
					this.ceshifenxiCount = data.data
				}
			})
		},
// 1234 竖
		ceshifenxiChat1() {
			this.$nextTick(()=>{

				var ceshifenxiChart1 = echarts.init(document.getElementById("ceshifenxiChart1"),'macarons');
				this.$http({
					url: "ceshifenxi/typeStat/ceshijieguo/renwumingcheng",
					method: "get",
				}).then(({ data }) => {
					if (data && data.code === 0) {
						let res = data.data;
						let xAxis = [];
						let yAxis1 = [];
						let yAxis2 = [];
						let yAxis3 = [];
						let yAxis4 = [];
						let pArray = []
						for(let i=0;i<res.length;i++){
							if(this.boardBase&&i==this.boardBase.barNum){
								break;
							}
							xAxis.push(res[i].renwumingcheng);
							yAxis1.push(parseFloat((res[i].优)));
							yAxis2.push(parseFloat((res[i].良)));
							yAxis3.push(parseFloat((res[i].中)));
							yAxis4.push(parseFloat((res[i].差)));
							pArray.push({
								name: res[i].ceshijieguo
							})
						}
						var option = {};
						let titleObj = this.bar.title
						titleObj.text = '测试结果情况'
						
						const legendObj = this.bar.legend
						let tooltipObj = {trigger: 'axis'}
						tooltipObj = Object.assign(tooltipObj , this.bar.tooltip?this.bar.tooltip:{})
						let xAxisObj = this.bar.xAxis
						xAxisObj.type = 'category'
						xAxisObj.data = xAxis
						
						let yAxisObj = this.bar.yAxis
						yAxisObj.type = 'value'
						let seriesObj = [
							{
								name: '优',
								data: yAxis1,
								type: 'bar',
							},
							{
								name: '良',
								data: yAxis2,
								type: 'bar',
							},
							{
								name: '中',
								data: yAxis3,
								type: 'bar',
							},
							{
								name: '差',
								data: yAxis4,
								type: 'bar',
							},
						]
						
						for (let i in seriesObj) {
							seriesObj[i] = Object.assign(seriesObj[i] , this.bar.series)
						}
						const gridObj = this.bar.grid
						option = {
							backgroundColor: this.bar.backgroundColor,
							color: this.bar.color,
							title: titleObj,
							legend: legendObj,
							grid: gridObj,
							tooltip: tooltipObj,
							xAxis: xAxisObj,
							yAxis: yAxisObj,
							series: seriesObj,
						};
						// 使用刚指定的配置项和数据显示图表。
						ceshifenxiChart1.setOption(option);
				
						//根据窗口的大小变动图表
						window.onresize = function() {
							ceshifenxiChart1.resize();
						};
					}else{
						this.$message({
							message: data.msg,
							type: "warning",
							duration: 1500,
						})
					}
				});
			})
		},


	}
};
</script>
